module RefModule(x,y,CLR,C,Q);input x,y;
wire g;
input CLR, C;
reg unused_tmp;
output Q;


assign g = x*y;


always @(posedge C or posedge CLR)
    begin 
      if (CLR) 
        unused_tmp <= 4'b0000; 
      else 
        unused_tmp <= unused_tmp + g; 
    end 

assign Q = unused_tmp; 

endmodule
